/*! La Main Occulte - v2.0 Simple */
(function () {
  function initBurger() {
    var b = document.querySelector(".burger"),
      n = document.querySelector(".nav-links"),
      o = document.querySelector("#menuOverlay");
    if (b && n && o) {
      b.addEventListener("click", function () {
        n.classList.toggle("nav-active");
        b.classList.toggle("toggle");
        o.classList.toggle("active");
      });
      n.querySelectorAll("a").forEach(function (l) {
        l.addEventListener("click", function () {
          n.classList.remove("nav-active");
          b.classList.remove("toggle");
          o.classList.remove("active");
        });
      });
      o.addEventListener("click", function () {
        n.classList.remove("nav-active");
        b.classList.remove("toggle");
        o.classList.remove("active");
      });
    }
  }

  function updateCountdown() {
    var d = document.getElementById("days"),
      h = document.getElementById("hours"),
      m = document.getElementById("minutes"),
      s = document.getElementById("seconds"),
      mini = document.getElementById("miniCountDays");

    // Sortir si aucun élément compteur n'existe sur la page
    if (!d && !h && !m && !s && !mini) return;

    var festival = new Date("October 31, 2026 10:00:00").getTime(),
      now = new Date().getTime(),
      diff = festival - now;

    if (diff < 0) {
      if (d) d.textContent = "00";
      if (h) h.textContent = "00";
      if (m) m.textContent = "00";
      if (s) s.textContent = "00";
      if (mini) mini.textContent = "0";
      return;
    }

    var days = Math.floor(diff / 86400000),
      hours = Math.floor((diff % 86400000) / 3600000),
      minutes = Math.floor((diff % 3600000) / 60000),
      seconds = Math.floor((diff % 60000) / 1000);

    if (d) d.textContent = days < 10 ? "0" + days : days;
    if (h) h.textContent = hours < 10 ? "0" + hours : hours;
    if (m) m.textContent = minutes < 10 ? "0" + minutes : minutes;
    if (s) s.textContent = seconds < 10 ? "0" + seconds : seconds;
    if (mini) mini.textContent = days;
  }

  function initScroll() {
    var btn = document.getElementById("scrollIndicator"),
      section = document.getElementById("introSection");
    if (btn && section) {
      btn.addEventListener("click", function () {
        section.scrollIntoView({ behavior: "smooth", block: "start" });
      });
    }

  }

  function initParticles() {
    var container = document.getElementById("heroParticles");
    if (!container) {
      setTimeout(initParticles, 100);
      return;
    }
    if (container.children.length > 0) return;
    container.innerHTML = "";
    for (var i = 0; i < 45; i++) {
      var p = document.createElement("div");
      p.classList.add("particle");
      var left = Math.random() * 100,
        top = Math.random() * 100,
        size = 2 + Math.random() * 4,
        duration = 6 + Math.random() * 12,
        delay = 5 + Math.random() * 25,
        travelY = -80 - Math.random() * 120,
        dir = Math.random() > 0.5 ? 1 : -1;
      p.style.cssText =
        "left: " +
        left +
        "%; top: " +
        top +
        "%; width: " +
        size +
        "px; height: " +
        size +
        "px; --travelY: " +
        travelY +
        "px; --travelX: " +
        Math.random() * 60 * dir +
        "px; --duration: " +
        duration +
        "s; opacity: " +
        (0.3 + Math.random() * 0.5) +
        "; animation: particleFloat " +
        duration +
        "s ease-in-out infinite; animation-delay: " +
        delay +
        "s;";
      container.appendChild(p);
    }
  }

  function loadGallery() {
    var photos = document.getElementById("photosGrid"),
      videos = document.getElementById("videosGrid"),
      articles = document.getElementById("articlesGrid");

    if (photos) {
      var galleryData = [
        {
          img: "img/galerie/cj/samhain.jpg",
          title: "Jonglage de contact",
          desc: "Festival Samhain - Bernay",
        },
        {
          img: "img/galerie/diabolo/diabolo.png",
          title: "Diabolo",
          desc: "Manipulation du sablier volant",
        },
        {
          img: "img/galerie/bdd/devilstick.jpg",
          title: "Baton du diable",
          desc: "Figures tournoyantes",
        },
      ];
      photos.innerHTML = "";
      for (var i = 0; i < galleryData.length; i++) {
        var item = galleryData[i];
        var card = document.createElement("div");
        card.className = "galerie-card";
        card.setAttribute("role", "button");
        card.setAttribute("aria-label", item.title + " - " + item.desc);
        card.onclick = (function (img, title, desc) {
          return function () {
            window.openPhotoModal(img, title, desc);
          };
        })(item.img, item.title, item.desc);
        var cardImage = document.createElement("div");
        cardImage.className = "galerie-card-image";
        var img = document.createElement("img");
        img.src = item.img;
        img.alt = item.title;
        img.loading = "lazy";
        img.onerror = function () {
          this.src = "img/placeholder.jpg";
        };
        var overlay = document.createElement("div");
        overlay.className = "galerie-card-overlay";
        var icon = document.createElement("i");
        icon.className = "fas fa-search-plus";
        overlay.appendChild(icon);
        cardImage.appendChild(img);
        cardImage.appendChild(overlay);
        var cardInfo = document.createElement("div");
        cardInfo.className = "galerie-card-info";
        var h3 = document.createElement("h3");
        h3.textContent = item.title;
        var p = document.createElement("p");
        p.textContent = item.desc;
        cardInfo.appendChild(h3);
        cardInfo.appendChild(p);
        card.appendChild(cardImage);
        card.appendChild(cardInfo);
        photos.appendChild(card);
      }
    }

    if (articles) {
      articles.innerHTML =
        '<div class="article-card" onclick="openArticleModal(1)"><div class="article-image"><img src="img/presse/escapegame.jpg" alt="L\'escape game au festival Samhain" loading="lazy" onerror="this.src=\'img/placeholder.jpg\'"></div><div class="article-content"><span class="article-date">Octobre 2025</span><h3>L\'escape game au festival Samhain</h3><p>Retrouvez le coeur de la sorciere dans l\'ancienne prison...</p><button class="article-btn">Lire l\'article →</button></div></div><div class="article-card" onclick="openArticleModal(2)"><div class="article-image"><img src="img/presse/th.png" alt="Un pur moment de poesie" loading="lazy" onerror="this.src=\'img/placeholder.jpg\'"></div><div class="article-content"><span class="article-date">Aout 2016</span><h3>Un pur moment de poesie</h3><p>Un pur moment de poesie au festival...</p><button class="article-btn">Lire l\'article →</button></div></div><div class="article-card" onclick="openArticleModal(3)"><div class="article-image"><img src="img/presse/blancbuisson.jpg" alt="Le jongleur des Jonquerets" loading="lazy" onerror="this.src=\'img/placeholder.jpg\'"></div><div class="article-content"><span class="article-date">Aout 2018</span><h3>Le jongleur des Jonquerets</h3><p>Le jongleur des Jonquerets emerveille le public...</p><button class="article-btn">Lire l\'article →</button></div></div><div class="article-card" onclick="openArticleModal(4)"><div class="article-image"><img src="img/presse/neubourg.png" alt="Un jongleur insolite" loading="lazy" onerror="this.src=\'img/placeholder.jpg\'"></div><div class="article-content"><span class="article-date">Aout 2017</span><h3>Un jongleur insolite</h3><p>Un jongleur insolite sur le marche...</p><button class="article-btn">Lire l\'article →</button></div></div>';
    }
  }

  function initFilters() {
    var filters = document.querySelectorAll(".filter-btn"),
      photosSec = document.getElementById("photos-section"),
      videosSec = document.getElementById("videos-section"),
      articlesSec = document.getElementById("articles-section");
    if (filters.length) {
      for (var i = 0; i < filters.length; i++) {
        filters[i].addEventListener("click", function () {
          var val = this.getAttribute("data-filter");
          for (var j = 0; j < filters.length; j++) {
            filters[j].classList.remove("active");
          }
          this.classList.add("active");
          if (val === "all") {
            if (photosSec) photosSec.style.display = "block";
            if (videosSec) videosSec.style.display = "block";
            if (articlesSec) articlesSec.style.display = "block";
          } else if (val === "photos") {
            if (photosSec) photosSec.style.display = "block";
            if (videosSec) videosSec.style.display = "none";
            if (articlesSec) articlesSec.style.display = "none";
          } else if (val === "videos") {
            if (photosSec) photosSec.style.display = "none";
            if (videosSec) videosSec.style.display = "block";
            if (articlesSec) articlesSec.style.display = "none";
          } else if (val === "articles") {
            if (photosSec) photosSec.style.display = "none";
            if (videosSec) videosSec.style.display = "none";
            if (articlesSec) articlesSec.style.display = "block";
          }
        });
      }
    }
  }

  function closeModal() {
    var modal = document.getElementById("galerieModal");
    if (modal) {
      modal.classList.remove("active");
      document.body.classList.remove("modal-open");
    }
  }

  window.openPhotoModal = function (img, title, desc) {
    var modal = document.getElementById("galerieModal"),
      modalImg = document.getElementById("modalImage"),
      caption = document.getElementById("modalCaption");
    if (modal && modalImg && caption) {
      modalImg.src = img;
      caption.textContent = title + " - " + desc;
      modal.classList.add("active");
      document.body.classList.add("modal-open");
    }
  };
  window.openArticleModal = function (id) {
    var articles = {
      1: {
        title: "L'escape game au festival Samhain",
        date: "Octobre 2025",
        image: "img/presse/escapegame.jpg",
        content:
          "<p>L'ancienne prison garde encore les traces d'un sombre maléfice. On raconte que le cœur de la plus puissante des sorcières y est enfermé depuis des siècles, protégé par des énigmes et des pièges.</p><p>Les participants doivent aider la sorcière Rutabaga à retrouver ses pouvoirs en relevant des défis de jonglerie et en résolvant des énigmes.</p>",
      },
      2: {
        title: "Un pur moment de poesie",
        date: "Aout 2016",
        image: "img/presse/th.png",
        content:
          "<p>Comme tous les lundis, sur le forum du Trez-hir, les badauds déambulent parmi les stands des artisans. Ce lundi n'a pas dérogé à la règle. On fit également des rencontres sympathiques, comme Aymeric qui fait du jonglage de contact. Un pur moment de poésie qui a accroché le regard des grands comme des petits, fascinés par les effets d'optique de la boule d'acrylique.</p>",
      },
      3: {
        title: "Le jongleur des Jonquerets",
        date: "Aout 2018",
        image: "img/presse/blancbuisson.jpg",
        content:
          "<p>Récemment aux Médiévales du Blanc-Buisson, on pouvait rencontrer un jongleur de contact: Aymeric Soetens, un habitant des Jonquerets-de-Livet. Même en regardant attentivement ce qu'il faisait, il donnait l'impression que sa balle flottait. C'était très bluffant.</p><p><strong>Lévitation</strong></p><p>Avec ses deux mains, le jongleur déplace la balle dans l'espace. L'essentiel de l'effet est basé sur l'impression de lévitation.</p>",
      },
      4: {
        title: "Un jongleur insolite",
        date: "Aout 2017",
        image: "img/presse/neubourg.png",
        content:
          "<p>Un jongleur insolite sur le marché du Neubourg. Vous avez peut-être déjà été séduits par sa dextérité. La boule qu'il fait passer d'une main dans l'autre semble totalement immobile. « Je fais du jonglage de contact, avec une balle en acrylique », explique le jeune homme.</p>",
      },
    };
    var art = articles[id];
    if (art) {
      var modal = document.getElementById("articleModalContent");
      if (!modal) {
        modal = document.createElement("div");
        modal.id = "articleModalContent";
        modal.className = "galerie-modal";
        modal.innerHTML =
          '<div class="galerie-modal-content" style="max-width:800px;background:#1a1e24;padding:2rem;border-radius:20px"><span class="modal-close-btn" id="articleModalClose">&times;</span><div style="clear:both"></div><img id="articleModalImg" style="width:100%;max-height:300px;object-fit:cover;border-radius:10px;margin-bottom:1rem"><h2 id="articleModalTitle" style="color:#c49a6c;font-family:Uncial,cursive"></h2><div class="article-modal-date" id="articleModalDate" style="color:#ff8400;margin-bottom:1rem;padding-bottom:0.5rem;border-bottom:1px solid rgba(107,45,156,0.3)"></div><div id="articleModalBody" style="color:#e0e0e0;line-height:1.8;font-size:1rem"></div></div>';
        document.body.appendChild(modal);
        document
          .getElementById("articleModalClose")
          .addEventListener("click", function () {
            modal.classList.remove("active");
            document.body.classList.remove("modal-open");
          });
      }
      document.getElementById("articleModalImg").src = art.image;
      document.getElementById("articleModalTitle").innerHTML = art.title;
      document.getElementById("articleModalDate").textContent = art.date;
      document.getElementById("articleModalBody").innerHTML = art.content;
      modal.classList.add("active");
      document.body.classList.add("modal-open");
    }
  };
  document.addEventListener("DOMContentLoaded", function () {
    initBurger();
    // Initialiser le compteur seulement si les éléments existent
    var hasCountdown =
      document.getElementById("days") ||
      document.getElementById("miniCountDays");
    if (hasCountdown) {
      updateCountdown();
      setInterval(updateCountdown, 1000);
    }
    initScroll();

    setTimeout(function () {
      initParticles();
    }, 100);

    // Vérifier si on est sur la page galerie
    if (
      document.getElementById("photosGrid") ||
      document.getElementById("videosGrid") ||
      document.getElementById("articlesGrid")
    ) {
      loadGallery();
      initFilters();
    }

    window.addEventListener("resize", function () {
      var c = document.getElementById("heroParticles");
      if (c && c.innerHTML) {
        initParticles();
      }
    });

    document.addEventListener("click", function (e) {
      var modal = document.getElementById("galerieModal");
      if (e.target === modal) {
        closeModal();
      }
      var artModal = document.getElementById("articleModalContent");
      if (e.target === artModal) {
        artModal.classList.remove("active");
        document.body.classList.remove("modal-open");
      }
    });

    document.addEventListener("keydown", function (e) {
      if (e.key === "Escape") {
        closeModal();
        var am = document.getElementById("articleModalContent");
        if (am) {
          am.classList.remove("active");
        }
        document.body.classList.remove("modal-open");
      }
    });
  });
})();
